#[derive(Debug)]
struct InsecureTlsVerifier {
    supported_schemes: Vec<SignatureScheme>,
}

impl ServerCertVerifier for InsecureTlsVerifier {
    fn verify_server_cert(
        &self,
        _end_entity: &CertificateDer<'_>,
        _intermediates: &[CertificateDer<'_>],
        _server_name: &ServerName<'_>,
        _ocsp_response: &[u8],
        _now: rustls::pki_types::UnixTime,
    ) -> Result<ServerCertVerified, rustls::Error> {
        Ok(ServerCertVerified::assertion())
    }

    fn verify_tls12_signature(
        &self,
        _message: &[u8],
        _cert: &CertificateDer<'_>,
        _dss: &DigitallySignedStruct,
    ) -> Result<HandshakeSignatureValid, rustls::Error> {
        Ok(HandshakeSignatureValid::assertion())
    }

    fn verify_tls13_signature(
        &self,
        _message: &[u8],
        _cert: &CertificateDer<'_>,
        _dss: &DigitallySignedStruct,
    ) -> Result<HandshakeSignatureValid, rustls::Error> {
        Ok(HandshakeSignatureValid::assertion())
    }

    fn supported_verify_schemes(&self) -> Vec<SignatureScheme> {
        self.supported_schemes.clone()
    }
}

impl ActiveProcess {
    pub(crate) fn new(
        kernel_pid: u32,
        kernel_handle: KernelProcessHandle,
        runtime: GuestRuntimeKind,
        execution: ActiveExecution,
    ) -> Self {
        Self {
            kernel_pid,
            kernel_handle,
            kernel_stdin_writer_fd: None,
            tty_master_fd: None,
            runtime,
            detached: false,
            execution,
            guest_cwd: String::from("/"),
            env: BTreeMap::new(),
            host_cwd: PathBuf::from("/"),
            host_write_dirty: false,
            mapped_host_fds: BTreeMap::new(),
            next_mapped_host_fd: MAPPED_HOST_FD_START,
            pending_execution_events: VecDeque::new(),
            pending_self_signal_exit: None,
            child_processes: BTreeMap::new(),
            next_child_process_id: 0,
            http_servers: BTreeMap::new(),
            pending_http_requests: BTreeMap::new(),
            http2: Default::default(),
            tcp_listeners: BTreeMap::new(),
            next_tcp_listener_id: 0,
            tcp_sockets: BTreeMap::new(),
            next_tcp_socket_id: 0,
            tcp_port_reservations: BTreeMap::new(),
            next_tcp_port_reservation_id: 0,
            unix_listeners: BTreeMap::new(),
            next_unix_listener_id: 0,
            unix_sockets: BTreeMap::new(),
            next_unix_socket_id: 0,
            udp_sockets: BTreeMap::new(),
            next_udp_socket_id: 0,
            python_sockets: BTreeMap::new(),
            next_python_socket_id: 0,
            cipher_sessions: BTreeMap::new(),
            next_cipher_session_id: 0,
            diffie_hellman_sessions: BTreeMap::new(),
            next_diffie_hellman_session_id: 0,
            sqlite_databases: BTreeMap::new(),
            next_sqlite_database_id: 0,
            sqlite_statements: BTreeMap::new(),
            next_sqlite_statement_id: 0,
            tty_master_owner: None,
            tty_raw_mode_generation: None,
            deferred_kernel_wait_rpc: None,
            module_resolution_cache: agentos_execution::LocalModuleResolutionCache::default(),
        }
    }

    pub(crate) fn queue_pending_execution_event(
        &mut self,
        event: ActiveExecutionEvent,
    ) -> Result<(), SidecarError> {
        if self.pending_execution_events.len() >= MAX_PROCESS_EVENT_QUEUE {
            return Err(process_event_queue_overflow_error());
        }
        self.pending_execution_events.push_back(event);
        Ok(())
    }

    pub(crate) fn with_host_cwd(mut self, host_cwd: PathBuf) -> Self {
        self.host_cwd = host_cwd;
        self
    }

    pub(crate) fn mark_host_write_dirty(&mut self) {
        self.host_write_dirty = true;
    }

    pub(crate) fn host_write_dirty_recursive(&self) -> bool {
        self.host_write_dirty
            || self
                .child_processes
                .values()
                .any(ActiveProcess::host_write_dirty_recursive)
    }

    pub(crate) fn clean_host_writes_are_observable_recursive(&self) -> bool {
        matches!(
            self.execution,
            ActiveExecution::Javascript(_) | ActiveExecution::Python(_) | ActiveExecution::Wasm(_)
        ) && self
            .child_processes
            .values()
            .all(ActiveProcess::clean_host_writes_are_observable_recursive)
    }

    pub(crate) fn with_guest_cwd(mut self, guest_cwd: String) -> Self {
        self.guest_cwd = guest_cwd;
        self
    }

    pub(crate) fn with_env(mut self, env: BTreeMap<String, String>) -> Self {
        self.env = env;
        self
    }

    pub(crate) fn with_kernel_stdin_writer_fd(mut self, fd: u32) -> Self {
        self.kernel_stdin_writer_fd = Some(fd);
        self
    }

    pub(crate) fn with_tty_master_fd(mut self, fd: Option<u32>) -> Self {
        self.tty_master_fd = fd;
        self
    }

    pub(crate) fn with_detached(mut self, detached: bool) -> Self {
        self.detached = detached;
        self
    }

    pub(crate) fn allocate_mapped_host_fd(&mut self, fd: ActiveMappedHostFd) -> u32 {
        let handle = self.next_mapped_host_fd;
        self.next_mapped_host_fd = self
            .next_mapped_host_fd
            .checked_add(1)
            .unwrap_or(MAPPED_HOST_FD_START);
        self.mapped_host_fds.insert(handle, fd);
        handle
    }

    pub(crate) fn mapped_host_fd(&self, fd: u32) -> Option<&ActiveMappedHostFd> {
        self.mapped_host_fds.get(&fd)
    }

    pub(crate) fn mapped_host_fd_mut(&mut self, fd: u32) -> Option<&mut ActiveMappedHostFd> {
        self.mapped_host_fds.get_mut(&fd)
    }

    pub(crate) fn close_mapped_host_fd(&mut self, fd: u32) -> bool {
        self.mapped_host_fds.remove(&fd).is_some()
    }

    pub(crate) fn allocate_child_process_id(&mut self) -> String {
        self.next_child_process_id += 1;
        format!("child-{}", self.next_child_process_id)
    }

    fn allocate_tcp_listener_id(&mut self) -> String {
        self.next_tcp_listener_id += 1;
        format!("listener-{}", self.next_tcp_listener_id)
    }

    fn allocate_tcp_socket_id(&mut self) -> String {
        self.next_tcp_socket_id += 1;
        format!("socket-{}", self.next_tcp_socket_id)
    }

    fn allocate_tcp_port_reservation_id(&mut self) -> String {
        self.next_tcp_port_reservation_id += 1;
        format!("tcp-port-reservation-{}", self.next_tcp_port_reservation_id)
    }

    fn allocate_unix_listener_id(&mut self) -> String {
        self.next_unix_listener_id += 1;
        format!("unix-listener-{}", self.next_unix_listener_id)
    }

    fn allocate_unix_socket_id(&mut self) -> String {
        self.next_unix_socket_id += 1;
        format!("unix-socket-{}", self.next_unix_socket_id)
    }

    fn allocate_udp_socket_id(&mut self) -> String {
        self.next_udp_socket_id += 1;
        format!("udp-socket-{}", self.next_udp_socket_id)
    }

    pub(crate) fn network_resource_counts(&self) -> NetworkResourceCounts {
        let mut counts = NetworkResourceCounts {
            sockets: self.http_servers.len()
                + self.tcp_listeners.len()
                + self.tcp_sockets.len()
                + self.unix_listeners.len()
                + self.unix_sockets.len()
                + self.udp_sockets.len()
                + self.python_sockets.len(),
            connections: self.tcp_sockets.len() + self.unix_sockets.len(),
        };
        if let Ok(http2) = self.http2.shared.lock() {
            counts.sockets += http2.servers.len() + http2.sessions.len();
            counts.connections += http2.sessions.len();
        }

        for child in self.child_processes.values() {
            let child_counts = child.network_resource_counts();
            counts.sockets += child_counts.sockets;
            counts.connections += child_counts.connections;
        }

        counts
    }

    fn sidecar_only_network_resource_counts(&self) -> NetworkResourceCounts {
        let mut counts = NetworkResourceCounts {
            sockets: self.http_servers.len()
                + self
                    .tcp_listeners
                    .values()
                    .filter(|listener| listener.kernel_socket_id.is_none())
                    .count()
                + self
                    .tcp_sockets
                    .values()
                    .filter(|socket| socket.kernel_socket_id.is_none())
                    .count()
                + self.unix_listeners.len()
                + self.unix_sockets.len()
                + self
                    .udp_sockets
                    .values()
                    .filter(|socket| socket.kernel_socket_id.is_none())
                    .count()
                + self.python_sockets.len(),
            connections: self
                .tcp_sockets
                .values()
                .filter(|socket| socket.kernel_socket_id.is_none())
                .count()
                + self.unix_sockets.len(),
        };
        if let Ok(http2) = self.http2.shared.lock() {
            counts.sockets += http2.servers.len() + http2.sessions.len();
            counts.connections += http2.sessions.len();
        }

        for child in self.child_processes.values() {
            let child_counts = child.sidecar_only_network_resource_counts();
            counts.sockets += child_counts.sockets;
            counts.connections += child_counts.connections;
        }

        counts
    }
}

fn poll_tool_process_event(
    execution: &ToolExecution,
) -> Result<Option<ActiveExecutionEvent>, SidecarError> {
    let event = execution
        .pending_events
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner())
        .pop_front();
    if event.is_some() {
        return Ok(event);
    }
    if execution.events_overflowed.load(Ordering::Relaxed) {
        return Err(process_event_queue_overflow_error());
    }
    Ok(None)
}

fn descendant_pending_execution_event_capacity(
    root: &ActiveProcess,
    child_path: &[&str],
) -> Option<usize> {
    let mut child = root;
    for child_process_id in child_path {
        child = child.child_processes.get(*child_process_id)?;
    }
    Some(MAX_PROCESS_EVENT_QUEUE.saturating_sub(child.pending_execution_events.len()))
}

fn poll_child_execution_after_exit(
    child: &mut ActiveProcess,
    wait: Duration,
) -> Result<Option<ActiveExecutionEvent>, SidecarError> {
    match child.execution.poll_event_blocking(wait) {
        Ok(event) => Ok(event),
        Err(SidecarError::Execution(message))
            if child.runtime == GuestRuntimeKind::WebAssembly
                && message == WasmExecutionError::EventChannelClosed.to_string() =>
        {
            Ok(None)
        }
        Err(error) => Err(error),
    }
}

fn closed_javascript_event_channel(message: &str) -> bool {
    message == "guest JavaScript event channel closed unexpectedly"
}

fn closed_python_event_channel(message: &str) -> bool {
    message == "guest Python event channel closed unexpectedly"
}

fn closed_wasm_event_channel(message: &str) -> bool {
    message == WasmExecutionError::EventChannelClosed.to_string()
}

fn missing_vm_error(vm_id: &str) -> SidecarError {
    SidecarError::InvalidState(format!("VM {vm_id} is no longer active"))
}

fn missing_process_error(vm_id: &str, process_id: &str) -> SidecarError {
    SidecarError::InvalidState(format!(
        "VM {vm_id} no longer has active process {process_id}"
    ))
}

/// Map a shared guest-kernel-call dispatcher error into a sidecar error,
/// preserving POSIX errno codes (`ECODE: message`) as kernel errors so guest
/// callers observe Linux-faithful failures, mirroring the filesystem path.
fn guest_kernel_core_error(error: agentos_native_sidecar_core::SidecarCoreError) -> SidecarError {
    let message = error.to_string();
    let is_errno = message.split_once(':').is_some_and(|(code, _)| {
        code.len() >= 2
            && code.starts_with('E')
            && code[1..]
                .bytes()
                .all(|byte| byte.is_ascii_uppercase() || byte.is_ascii_digit() || byte == b'_')
    });
    if is_errno {
        SidecarError::Kernel(message)
    } else {
        SidecarError::InvalidState(message)
    }
}

fn is_broken_pipe_error(error: &SidecarError) -> bool {
    matches!(error, SidecarError::Execution(message) if message.contains("Broken pipe") || message.contains("os error 32") || message.contains("EPIPE"))
}

fn javascript_child_process_gone_error(process_id: &str, child_path: &[&str]) -> SidecarError {
    let child_label = if child_path.is_empty() {
        process_id.to_owned()
    } else {
        format!("{process_id}/{}", child_path.join("/"))
    };
    SidecarError::Execution(format!(
        "ECHILD: child_process {child_label} is no longer available"
    ))
}

fn is_javascript_child_process_gone_error(error: &SidecarError) -> bool {
    matches!(
        error,
        SidecarError::Execution(message) if guest_errno_code(message) == Some("ECHILD")
    )
}

fn loopback_tls_transport_registry(
) -> &'static Mutex<BTreeMap<String, Weak<crate::state::LoopbackTlsTransportPair>>> {
    static REGISTRY: OnceLock<
        Mutex<BTreeMap<String, Weak<crate::state::LoopbackTlsTransportPair>>>,
    > = OnceLock::new();
    REGISTRY.get_or_init(|| Mutex::new(BTreeMap::new()))
}

#[cfg(test)]
#[allow(dead_code)]
pub(crate) fn loopback_tls_registry_len() -> usize {
    loopback_tls_transport_registry()
        .lock()
        .expect("loopback TLS transport registry lock poisoned")
        .len()
}

#[cfg(test)]
pub(crate) fn loopback_tls_registry_contains(key: &str) -> bool {
    loopback_tls_transport_registry()
        .lock()
        .expect("loopback TLS transport registry lock poisoned")
        .contains_key(key)
}

fn loopback_tls_transport_key(
    vm_id: &str,
    socket_id: SocketId,
    peer_socket_id: SocketId,
) -> String {
    let (lower, higher) = if socket_id <= peer_socket_id {
        (socket_id, peer_socket_id)
    } else {
        (peer_socket_id, socket_id)
    };
    format!("{vm_id}:{lower}:{higher}")
}

fn loopback_tls_endpoint(
    vm_id: &str,
    socket_id: SocketId,
    peer_socket_id: SocketId,
) -> Result<crate::state::LoopbackTlsEndpoint, SidecarError> {
    let key = loopback_tls_transport_key(vm_id, socket_id, peer_socket_id);
    let registry = loopback_tls_transport_registry();
    let mut transports = registry.lock().map_err(|_| {
        SidecarError::InvalidState(String::from(
            "loopback TLS transport registry lock poisoned",
        ))
    })?;
    transports.retain(|_, pair| pair.strong_count() > 0);
    let pair = transports
        .get(&key)
        .and_then(Weak::upgrade)
        .unwrap_or_else(|| {
            let pair = Arc::new(crate::state::LoopbackTlsTransportPair {
                state: Mutex::new(crate::state::LoopbackTlsTransportPairState::default()),
                ready: std::sync::Condvar::new(),
            });
            transports.insert(key.clone(), Arc::downgrade(&pair));
            pair
        });
    Ok(crate::state::LoopbackTlsEndpoint {
        pair,
        is_lower_socket: socket_id <= peer_socket_id,
        poll_timeout: TCP_SOCKET_POLL_TIMEOUT,
        registry_key: Some(key),
    })
}

impl crate::state::LoopbackTlsEndpoint {
    fn set_poll_timeout(&mut self, timeout: Duration) {
        self.poll_timeout = timeout;
    }

    fn interrupt_reader(pair: &Arc<crate::state::LoopbackTlsTransportPair>, is_lower_socket: bool) {
        if let Ok(mut state) = pair.state.lock() {
            if is_lower_socket {
                state.lower_read_interrupt = true;
            } else {
                state.higher_read_interrupt = true;
            }
            pair.ready.notify_all();
        }
    }

    fn shutdown_write(&self) -> Result<(), SidecarError> {
        let mut state = self.pair.state.lock().map_err(|_| {
            SidecarError::InvalidState(String::from("loopback TLS transport lock poisoned"))
        })?;
        if self.is_lower_socket {
            state.lower_write_closed = true;
        } else {
            state.higher_write_closed = true;
        }
        self.pair.ready.notify_all();
        Ok(())
    }

    fn close_endpoint(&self) -> Result<(), SidecarError> {
        let mut state = self.pair.state.lock().map_err(|_| {
            SidecarError::InvalidState(String::from("loopback TLS transport lock poisoned"))
        })?;
        if self.is_lower_socket {
            state.lower_write_closed = true;
            state.lower_closed = true;
        } else {
            state.higher_write_closed = true;
            state.higher_closed = true;
        }
        self.pair.ready.notify_all();
        Ok(())
    }
}

impl LoopbackTlsPendingWriteHandle {
    pub(crate) fn new(endpoint: &crate::state::LoopbackTlsEndpoint) -> Self {
        Self {
            state: Arc::new(Mutex::new(LoopbackTlsPendingWriteState {
                buffer: Vec::new(),
                warned_near_cap: false,
                flushing: false,
                defer_shutdown_write: false,
                failure_message: None,
            })),
            tls_handshake_complete: Arc::new(AtomicBool::new(false)),
            failed: Arc::new(AtomicBool::new(false)),
            pair: Arc::clone(&endpoint.pair),
            is_lower_socket: endpoint.is_lower_socket,
            handshake_started_at: Instant::now(),
        }
    }

    fn failure_error(&self) -> SidecarError {
        let message = self
            .state
            .lock()
            .ok()
            .and_then(|state| state.failure_message.clone())
            .unwrap_or_else(|| String::from("loopback TLS pending write failed"));
        SidecarError::Execution(message)
    }

    fn mark_failed(&self, message: impl Into<String>) {
        self.failed.store(true, Ordering::SeqCst);
        if let Ok(mut state) = self.state.lock() {
            state.buffer.clear();
            state.flushing = false;
            state.defer_shutdown_write = false;
            state.failure_message = Some(message.into());
        }
    }

    fn clear_for_close(&self) {
        self.mark_failed("loopback TLS socket closed before buffered writes flushed");
    }

    fn fail_if_pending(&self, message: impl Into<String>) {
        let has_pending = self
            .state
            .lock()
            .map(|state| !state.buffer.is_empty() || state.flushing || state.defer_shutdown_write)
            .unwrap_or(true);
        if has_pending {
            self.mark_failed(message);
        }
    }

    fn should_buffer_write(&self) -> Result<bool, SidecarError> {
        if self.failed.load(Ordering::SeqCst) {
            return Err(self.failure_error());
        }
        let state = self.state.lock().map_err(|_| {
            SidecarError::InvalidState(String::from("loopback TLS pending write lock poisoned"))
        })?;
        Ok(!self.tls_handshake_complete.load(Ordering::SeqCst)
            || !state.buffer.is_empty()
            || state.flushing)
    }

    pub(crate) fn append_write(&self, contents: &[u8]) -> Result<(), SidecarError> {
        if self.failed.load(Ordering::SeqCst) {
            return Err(self.failure_error());
        }
        let mut state = self.state.lock().map_err(|_| {
            SidecarError::InvalidState(String::from("loopback TLS pending write lock poisoned"))
        })?;
        let observed = state.buffer.len().saturating_add(contents.len());
        if observed > LOOPBACK_TLS_PENDING_WRITE_BUFFER_BYTES {
            return Err(SidecarError::Execution(format!(
                "loopback TLS pending write buffer exceeded: {observed} bytes > {cap} bytes (limit: loopback TLS pending write buffer)",
                cap = LOOPBACK_TLS_PENDING_WRITE_BUFFER_BYTES
            )));
        }
        if !state.warned_near_cap && observed >= LOOPBACK_TLS_PENDING_WRITE_WARNING_BYTES {
            state.warned_near_cap = true;
            tracing::warn!(
                limit = "loopback_tls_pending_write_buffer",
                observed_bytes = observed,
                cap_bytes = LOOPBACK_TLS_PENDING_WRITE_BUFFER_BYTES,
                fill_percent =
                    (observed as f64 / LOOPBACK_TLS_PENDING_WRITE_BUFFER_BYTES as f64) * 100.0,
                wired = "invariant.loopbackTlsPendingWriteBufferBytes",
                "loopback TLS pending write buffer is near capacity"
            );
        }
        state.buffer.extend_from_slice(contents);
        Ok(())
    }

    fn defer_shutdown_write(&self) -> Result<(), SidecarError> {
        if self.failed.load(Ordering::SeqCst) {
            return Err(self.failure_error());
        }
        let mut state = self.state.lock().map_err(|_| {
            SidecarError::InvalidState(String::from("loopback TLS pending write lock poisoned"))
        })?;
        state.defer_shutdown_write = true;
        Ok(())
    }

    fn take_buffer_for_flush(&self) -> Result<Option<Vec<u8>>, SidecarError> {
        let mut state = self.state.lock().map_err(|_| {
            SidecarError::InvalidState(String::from("loopback TLS pending write lock poisoned"))
        })?;
        if state.buffer.is_empty() {
            return Ok(None);
        }
        state.flushing = true;
        Ok(Some(std::mem::take(&mut state.buffer)))
    }

    fn finish_flush(&self) {
        if let Ok(mut state) = self.state.lock() {
            state.flushing = false;
        }
    }

    fn take_deferred_shutdown_write(&self) -> Result<bool, SidecarError> {
        let mut state = self.state.lock().map_err(|_| {
            SidecarError::InvalidState(String::from("loopback TLS pending write lock poisoned"))
        })?;
        if state.buffer.is_empty() && !state.flushing && state.defer_shutdown_write {
            state.defer_shutdown_write = false;
            return Ok(true);
        }
        Ok(false)
    }

    fn interrupt_own_reader(&self) {
        crate::state::LoopbackTlsEndpoint::interrupt_reader(&self.pair, self.is_lower_socket);
    }
}

fn parse_tls_client_hello_from_bytes(
    buffer: &[u8],
) -> Result<Option<JavascriptTlsClientHello>, SidecarError> {
    if buffer.is_empty() {
        return Ok(None);
    }

    let mut acceptor = rustls::server::Acceptor::default();
    let mut cursor = Cursor::new(buffer);
    acceptor.read_tls(&mut cursor).map_err(sidecar_net_error)?;
    let Some(accepted) = acceptor.accept().map_err(|(error, _)| {
        SidecarError::Execution(format!("failed to parse TLS client hello: {error}"))
    })?
    else {
        return Ok(None);
    };
    let client_hello = accepted.client_hello();
    let alpn_protocols = client_hello.alpn().map(|protocols| {
        protocols
            .filter_map(|protocol| String::from_utf8(protocol.to_vec()).ok())
            .collect::<Vec<_>>()
    });
    Ok(Some(JavascriptTlsClientHello {
        servername: client_hello.server_name().map(str::to_owned),
        alpn_protocols,
    }))
}

fn peek_loopback_tls_client_hello(
    vm_id: &str,
    socket_id: SocketId,
    peer_socket_id: SocketId,
) -> Result<Option<JavascriptTlsClientHello>, SidecarError> {
    let key = loopback_tls_transport_key(vm_id, socket_id, peer_socket_id);
    let registry = loopback_tls_transport_registry();
    let pair = registry
        .lock()
        .map_err(|_| {
            SidecarError::InvalidState(String::from(
                "loopback TLS transport registry lock poisoned",
            ))
        })?
        .get(&key)
        .and_then(Weak::upgrade);
    let Some(pair) = pair else {
        return Ok(None);
    };
    let is_lower_socket = socket_id <= peer_socket_id;
    let state = pair.state.lock().map_err(|_| {
        SidecarError::InvalidState(String::from("loopback TLS transport lock poisoned"))
    })?;
    let buffered = if is_lower_socket {
        state.higher_to_lower.iter().copied().collect::<Vec<_>>()
    } else {
        state.lower_to_higher.iter().copied().collect::<Vec<_>>()
    };
    drop(state);
    parse_tls_client_hello_from_bytes(&buffered)
}

fn wait_for_loopback_peer_socket_id(
    kernel: &SidecarKernel,
    socket_id: SocketId,
) -> Option<SocketId> {
    // Keep the total wait budget aligned with the previous ~500ms poll window.
    let deadline = Instant::now() + Duration::from_millis(500);
    let mut backoff = Duration::from_micros(100);
    loop {
        if let Some(peer_socket_id) = kernel
            .socket_get(socket_id)
            .and_then(|record| record.peer_socket_id())
        {
            return Some(peer_socket_id);
        }
        let now = Instant::now();
        if now >= deadline {
            break;
        }
        std::thread::sleep(backoff.min(deadline.saturating_duration_since(now)));
        backoff = (backoff * 2).min(Duration::from_millis(1));
    }
    None
}

impl Drop for crate::state::LoopbackTlsEndpoint {
    fn drop(&mut self) {
        let _ = self.close_endpoint();

        // Eagerly prune this endpoint's registry entry once we are the last owner
        // of the shared transport pair. Without this, the `Weak` entry survives
        // until the next `loopback_tls_endpoint()` call runs its lazy `retain()`,
        // so dead entries accumulate under intermittent use. We must NOT remove
        // the entry while a peer endpoint still shares the pair, otherwise a later
        // connection for the same socket pair would fail to find it and build a
        // mismatched fresh pair.
        let Some(key) = self.registry_key.take() else {
            return;
        };
        let Ok(mut transports) = loopback_tls_transport_registry().lock() else {
            // Lock poisoned: leave the entry for the lazy `retain()` to reclaim.
            return;
        };
        let should_remove = match transports.get(&key) {
            // Only prune when the registered entry still points at *our* pair and
            // `self` is its last strong owner. During `Drop` `self.pair` is still
            // alive, so a strong count of 1 (after dropping the temporary upgrade)
            // means no other endpoint references it.
            Some(weak) => match weak.upgrade() {
                Some(existing) => {
                    let same_pair = Arc::ptr_eq(&existing, &self.pair);
                    drop(existing);
                    same_pair && Arc::strong_count(&self.pair) <= 1
                }
                None => true,
            },
            None => false,
        };
        if should_remove {
            transports.remove(&key);
        }
    }
}

impl Read for crate::state::LoopbackTlsEndpoint {
    fn read(&mut self, buffer: &mut [u8]) -> std::io::Result<usize> {
        let mut state = self
            .pair
            .state
            .lock()
            .map_err(|_| std::io::Error::other("loopback TLS transport lock poisoned"))?;

        loop {
            let (peer_write_closed, peer_closed) = if self.is_lower_socket {
                (state.higher_write_closed, state.higher_closed)
            } else {
                (state.lower_write_closed, state.lower_closed)
            };

            let incoming = if self.is_lower_socket {
                &mut state.higher_to_lower
            } else {
                &mut state.lower_to_higher
            };

            if !incoming.is_empty() {
                let count = incoming.len().min(buffer.len());
                let (head, tail) = incoming.as_slices();
                let head_count = head.len().min(count);
                buffer[..head_count].copy_from_slice(&head[..head_count]);
                if head_count < count {
                    buffer[head_count..count].copy_from_slice(&tail[..count - head_count]);
                }
                incoming.drain(..count);
                return Ok(count);
            }

            if peer_write_closed || peer_closed {
                return Ok(0);
            }

            let read_interrupted = if self.is_lower_socket {
                std::mem::take(&mut state.lower_read_interrupt)
            } else {
                std::mem::take(&mut state.higher_read_interrupt)
            };
            if read_interrupted {
                return Err(std::io::Error::new(
                    std::io::ErrorKind::WouldBlock,
                    "loopback TLS transport read interrupted",
                ));
            }

            let (next_state, wait_result) = self
                .pair
                .ready
                .wait_timeout(state, self.poll_timeout)
                .map_err(|_| std::io::Error::other("loopback TLS transport lock poisoned"))?;
            state = next_state;
            if wait_result.timed_out() {
                return Err(std::io::Error::new(
                    std::io::ErrorKind::WouldBlock,
                    "loopback TLS transport read timed out",
                ));
            }
        }
    }
}

impl Write for crate::state::LoopbackTlsEndpoint {
    fn write(&mut self, buffer: &[u8]) -> std::io::Result<usize> {
        let mut state = self
            .pair
            .state
            .lock()
            .map_err(|_| std::io::Error::other("loopback TLS transport lock poisoned"))?;

        let peer_closed = if self.is_lower_socket {
            state.higher_closed
        } else {
            state.lower_closed
        };
        let outgoing = if self.is_lower_socket {
            &mut state.lower_to_higher
        } else {
            &mut state.higher_to_lower
        };
        if peer_closed {
            return Err(std::io::Error::new(
                std::io::ErrorKind::BrokenPipe,
                "loopback TLS peer is closed",
            ));
        }

        outgoing.extend(buffer.iter().copied());
        self.pair.ready.notify_all();
        Ok(buffer.len())
    }

    fn flush(&mut self) -> std::io::Result<()> {
        Ok(())
    }
}

#[cfg(test)]
mod loopback_tls_registry_tests {
    use super::{
        loopback_tls_endpoint, loopback_tls_registry_contains, loopback_tls_transport_key,
    };

    // Each test uses a unique vm_id so the process-global registry stays
    // partitioned across concurrently running tests.

    #[test]
    fn dropping_endpoint_removes_its_registry_entry() {
        let vm_id = "loopback-tls-drop-removes-entry";
        let key = loopback_tls_transport_key(vm_id, 1, 2);

        let endpoint = loopback_tls_endpoint(vm_id, 1, 2).expect("create endpoint");
        assert!(
            loopback_tls_registry_contains(&key),
            "registry should contain the key while the endpoint is alive"
        );

        drop(endpoint);
        assert!(
            !loopback_tls_registry_contains(&key),
            "registry entry must be pruned in the endpoint's Drop, not left for the lazy retain()"
        );
    }

    #[test]
    fn registry_entry_survives_until_last_peer_endpoint_drops() {
        let vm_id = "loopback-tls-shared-pair";
        let key = loopback_tls_transport_key(vm_id, 3, 4);

        // Both peers of a loopback connection share the same transport pair.
        let lower = loopback_tls_endpoint(vm_id, 3, 4).expect("create lower endpoint");
        let higher = loopback_tls_endpoint(vm_id, 4, 3).expect("create higher endpoint");
        assert!(loopback_tls_registry_contains(&key));

        // Dropping one peer must keep the entry, since the other peer still owns
        // the shared pair and a later connection must be able to find it.
        drop(lower);
        assert!(
            loopback_tls_registry_contains(&key),
            "entry must survive while a peer endpoint still shares the pair"
        );

        drop(higher);
        assert!(
            !loopback_tls_registry_contains(&key),
            "entry must be pruned once the last peer endpoint drops"
        );
    }
}

